insert into public.vehicle_specs (
  brand_id, model_id, trim, engine, fuel_type, transmission,
  source, source_url, metadata
)
select
  b.id,
  m.id,
  '1.8 TCT',
  '1.8 TCT',
  'Benzin',
  'Otomatik',
  'user_provided_catalog',
  'http://www.alfaromeo.com.tr/',
  '{"catalog_record_id":"2","engine_group":"1.8 TCT","engine_cc":1800,"historical_list_price_try":620000,"imported_from":"data/vehicle_variants_catalog.json"}'::jsonb
from public.brands b
join public.models m on m.brand_id = b.id
where lower(trim(b.name)) = lower(trim('Alfa Romeo'))
  and lower(trim(m.name)) = lower(trim('4C Spider'))
on conflict (
  model_id,
  coalesce(nullif(btrim(year), ''), 'any'),
  coalesce(nullif(btrim("trim"), ''), 'standard'),
  source
) do update set
  brand_id = excluded.brand_id,
  engine = excluded.engine,
  fuel_type = excluded.fuel_type,
