  source, source_url, metadata
)
select
  b.id,
  m.id,
  '2.0 150BG Sport Plus',
  '2.0 150BG',
  'Dizel',
  'Otomatik',
  'user_provided_catalog',
  'http://www.bmw.com.tr/',
  '{"catalog_record_id":"166","engine_group":"2.0 150BG","engine_cc":2000,"historical_list_price_try":250700,"imported_from":"data/vehicle_variants_catalog.json"}'::jsonb
from public.brands b
join public.models m on m.brand_id = b.id
where lower(trim(b.name)) = lower(trim('Bmw'))
  and lower(trim(m.name)) = lower(trim('318d Sedan'))
on conflict (
  model_id,
  coalesce(nullif(btrim(year), ''), 'any'),
  coalesce(nullif(btrim("trim"), ''), 'standard'),
  source
) do update set
  brand_id = excluded.brand_id,
  engine = excluded.engine,
  fuel_type = excluded.fuel_type,
  transmission = excluded.transmission,
  source_url = excluded.source_url,
  metadata = excluded.metadata,
  updated_at = now();

